from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql, Error

app = Flask(__name__)

# Database connection details - Replace with your actual credentials
DB_HOST = "your_db_host"
DB_NAME = "your_db_name"
DB_USER = "your_db_user"
DB_PASSWORD = "your_db_password"

def get_db_connection():
    try:
        conn = psycopg2.connect(
            host=DB_HOST,
            database=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD
        )
        return conn
    except Error as e:
        print(f"Error connecting to PostgreSQL database: {e}")
        return None

@app.route('/query_data', methods=['POST'])
def query_data():
    data = request.get_json()

    if not data:
        return jsonify({"error": "No input data provided"}), 400

    table_name = data.get('table_name')
    columns = data.get('columns')
    filters = data.get('filters') # e.g., [{"column": "age", "operator": ">", "value": 30}]
    order_by = data.get('order_by') # e.g., [{"column": "name", "direction": "ASC"}]
    limit = data.get('limit')
    offset = data.get('offset')

    if not table_name:
        return jsonify({"error": "Table name is required"}), 400

    conn = None
    cur = None
    try:
        conn = get_db_connection()
        if not conn:
            return jsonify({"error": "Database connection failed"}), 500
        cur = conn.cursor()

        # Build SELECT clause
        if columns:
            select_cols = [sql.Identifier(col) for col in columns]
            select_clause = sql.SQL(', ').join(select_cols)
        else:
            select_clause = sql.SQL('*')

        # Build FROM clause
        from_clause = sql.Identifier(table_name)

        # Build WHERE clause
        where_parts = []
        where_values = []
        if filters:
            for f in filters:
                col = f.get('column')
                op = f.get('operator')
                val = f.get('value')

                if not all([col, op, val is not None]):
                    return jsonify({"error": "Invalid filter format. Each filter requires 'column', 'operator', and 'value'."}), 400

                # Basic sanitization/validation of operator to prevent SQL injection
                allowed_operators = ['=', '!=', '<', '>', '<=', '>=', 'LIKE', 'ILIKE', 'IN', 'NOT IN']
                if op.upper() not in allowed_operators:
                    return jsonify({"error": f"Unsupported operator: {op}"}), 400

                if op.upper() in ['IN', 'NOT IN']:
                    if not isinstance(val, list):
                        return jsonify({"error": f"Value for operator '{op}' must be a list."}), 400
                    placeholders = sql.SQL(', ').join([sql.Literal(v) for v in val])
                    where_parts.append(sql.SQL('{} {} ({})').format(sql.Identifier(col), sql.SQL(op.upper()), placeholders))
                else:
                    where_parts.append(sql.SQL('{} {} %s').format(sql.Identifier(col), sql.SQL(op.upper())))
                    where_values.append(val)

        where_clause = sql.SQL(' WHERE ') + sql.SQL(' AND ').join(where_parts) if where_parts else sql.SQL('')

        # Build ORDER BY clause
        order_by_parts = []
        if order_by:
            for ob in order_by:
                col = ob.get('column')
                direction = ob.get('direction', 'ASC').upper()

                if not col:
                    return jsonify({"error": "Order by item requires 'column'."}), 400

                if direction not in ['ASC', 'DESC']:
                    return jsonify({"error": f"Invalid order direction: {direction}. Must be 'ASC' or 'DESC'."}), 400

                order_by_parts.append(sql.SQL('{} {}').format(sql.Identifier(col), sql.SQL(direction)))

        order_by_clause = sql.SQL(' ORDER BY ') + sql.SQL(', ').join(order_by_parts) if order_by_parts else sql.SQL('')

        # Build LIMIT and OFFSET clauses
        limit_clause = sql.SQL(' LIMIT %s') if limit is not None else sql.SQL('')
        offset_clause = sql.SQL(' OFFSET %s') if offset is not None else sql.SQL('')

        # Assemble the full query
        query = sql.SQL("SELECT {} FROM {} {} {} {} {}").format(
            select_clause,
            from_clause,
            where_clause,
            order_by_clause,
            limit_clause,
            offset_clause
        )

        # Prepare parameters for execution
        execute_params = where_values
        if limit is not None:
            execute_params.append(limit)
        if offset is not None:
            execute_params.append(offset)

        cur.execute(query, execute_params)
        rows = cur.fetchall()
        column_names = [desc[0] for desc in cur.description]

        results = []
        for row in rows:
            results.append(dict(zip(column_names, row)))

        return jsonify(results)

    except Error as e:
        print(f"Database error: {e}")
        return jsonify({"error": f"Database query failed: {e}"}), 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return jsonify({"error": f"An unexpected error occurred: {e}"}), 500
    finally:
        if cur:
            cur.close()
        if conn:
            conn.close()

if __name__ == '__main__':
    app.run(debug=True)